{
	if (NULL_var != _sp3DCurveBody)
		_sp3DCurveBody = NULL_var;
	
	if (NULL_var != _spTopSurfBody)
		_spTopSurfBody = NULL_var;

	if (NULL_var != _spBaseSurfBody)
		_spBaseSurfBody = NULL_var;

	if (NULL != _pGeomFactory)
		_pGeomFactory->Release(); _pGeomFactory = NULL;

	if (NULL != _pSoftConfig)
		_pSoftConfig->Release(); _pSoftConfig = NULL;

	if (NULL != _pCGMJournalList)
		_pCGMJournalList = NULL;

	if (NULL != _piMRFGrooveFeat)
		_piMRFGrooveFeat->Release(); _piMRFGrooveFeat = NULL;

	if (NULL != _piAlgoConfigServices)
		_piAlgoConfigServices->Release(); _piAlgoConfigServices = NULL;

	if (NULL_var != _spGSMFactory)
		_spGSMFactory->Release(); _spGSMFactory = NULL_var;

	if (NULL_var != _spProcReport)
	{
		_spProcReport->DeleteProcReport();
		_spProcReport = NULL_var;
	}

	if (_ListOfBodies.Size() > 0)
	{
		for (int i = 1; i <= _ListOfBodies.Size(); i++)
		{
			CATBody * iBody = _ListOfBodies[i];
			if (NULL != iBody)
			{
				iBody->Release();
				iBody = NULL;
			}
		}
		_ListOfBodies.RemoveAll();
	}

	if (NULL_var != _spSweepBody)
		_spSweepBody->Release(); _spSweepBody = NULL_var;

	_AngleRefIndexList.RemoveAll();
}



